#!/usr/bin/env bash
# topic-2.sh — —— 决策助手 for 调香师与香水.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="调香师与香水"
TOPIC="——"

usage() {
  cat <<EOF
topic-2.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 4 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-2.sh             # interactive
  ./topic-2.sh --dry-run   # walk through but no file
  ./topic-2.sh --json      # JSON to stdout
  ./topic-2.sh --explain   # show backing playbook rules + mental models
  ./topic-2.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 —— 主题下的 playbook 规则组合成交互树。

基于 4 条规则:
  • 如果 有人承诺「速成调香大师」或「软件/AI 替你调出好香」 → 则 判为外行/营销——tacit 的嗅觉记忆只能靠反复闻料内化（无书面记法、无捷径），工具与 AI 只是脚手架，最终评估/品
  • 如果 要选工具/原料供应 → 则 按身份分层——学习者用「方法（Jean Carles 法）+ 训练 kit + TGSC」、indie 用「小量供应商 
  • 如果 要「还原一支香的配方」 → 则 用 GC-MS + headspace 而非读 note 金字塔——金字塔是营销叙事/感知文案，不必对应实际用料
  • 如果 听到「pheromone 吸引异性 / therapeutic-grade 能治病 / 保证 24h 持久 / dupe → 则 识别为被资深从业者拒绝的营销话术、给一句机理反驳——这是行业价值观的试金石

相关心智模型:
  • codifiable 原料 ⇄ tacit 嗅觉记忆（第一性张力）: 这行可背诵的一半（原料、香料化学、accord 公式、挥发度、IFRA 限值）能进教科书；另一半——成为「the nose」的嗅觉记忆与品味——不可言传，只能靠每天盲嗅背料一克一克长出来。学校先让学徒
  • 暗示而非复刻：香水是「说真话的谎言」: 顶级调香不复刻自然，而是用（多为合成的）分子制造一个比真实更可信的**嗅觉幻觉**——Ellena 自称 illusionist，Ropion 的 Carnal Flower 是「扭曲/暗示一朵晚香玉

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "有人承诺「速成调香大师」或「软件/AI 替你调出好香」"
  "要选工具/原料供应"
  "要「还原一支香的配方」"
  "听到「pheromone 吸引异性 / therapeutic-grade 能治病 / 保证 24h 持久 / dupe 和原版一模一样」"
)
declare -a RULE_ACTIONS=(
  "判为外行/营销——tacit 的嗅觉记忆只能靠反复闻料内化（无书面记法、无捷径），工具与 AI 只是脚手架，最终评估/品味/accord 微调仍是人鼻工作"
  "按身份分层——学习者用「方法（Jean Carles 法）+ 训练 kit + TGSC」、indie 用「小量供应商 + 自带 IFRA 检测的轻量软件」、pro 用「公司调色板（含 captives）+ 企业 PLM + 内部 AI」；身份错配（indie 上企业 PLM、pro 用裸 Excel）是常见坑"
  "用 GC-MS + headspace 而非读 note 金字塔——金字塔是营销叙事/感知文案，不必对应实际用料"
  "识别为被资深从业者拒绝的营销话术、给一句机理反驳——这是行业价值观的试金石"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-2-decision"
fi
